/// <summary>
/// extension class for class <c>ETGITMCreatorTableGeneration</c>
/// </summary>
public class ETGITMCreatorTableGenerationV2 extends ETGITMCreatorTableGeneration
{
    private Map purchTableMap;
    private Map inventTransferTableMap;

}

