/// <summary>
/// build query to fetch outbound orders lines
/// </summary>
/// <returns>Query</returns>
public Query buildQuery()
{
    Query query = super();

    ITMCreatorOptions    shipCreatorOptionsLocal = this.parmShipCreatorOptions();
    QueryBuildDataSource qbd_InventTrans = query.dataSourceTable(tableNum(InventTrans));
    QueryBuildDataSource qbd_InventDim = query.dataSourceTable(tableNum(InventDim));
    QueryBuildDataSource qbd_InventTransOrigin = query.dataSourceTable(tableNum(InventTransOrigin));

    qbd_InventTrans.addSelectionField(fieldNum(InventTrans, Qty), SelectionField::Sum);
    qbd_InventTrans.addGroupByField(fieldNum(InventTrans, InventDimId));
    qbd_InventTrans.addGroupByField(fieldNum(InventTrans, ItemId));
    qbd_InventDim.addGroupByField(fieldNum(InventDim, InventSiteId));
    qbd_InventDim.addGroupByField(fieldNum(InventDim, InventLocationId));
    qbd_InventTransOrigin.addGroupByField(fieldNum(InventTransOrigin, InventTransId));

    if (this.includeSalesLineInQuery(shipCreatorOptionsLocal))
    {
        QueryBuildDataSource qbd_PurchLine = qbd_InventTransOrigin.addDataSource(tableNum(SalesLine));
        qbd_PurchLine.addLink(fieldNum(InventTransOrigin, InventTransId), fieldNum(SalesLine, InventTransId));
        qbd_PurchLine.joinMode(JoinMode::OuterJoin);
        qbd_PurchLine.addGroupByField(fieldNum(SalesLine, InventTransId));
        qbd_PurchLine.addGroupByField(fieldNum(SalesLine, SalesUnit));
        qbd_PurchLine.fetchMode(QueryFetchMode::One2One);
    }

    if (this.includInventTransferLineInQuery(shipCreatorOptionsLocal))
    {
        QueryBuildDataSource qbd_InventTransferLine = qbd_InventTransOrigin.addDataSource(tableNum(InventTransferLine));
        qbd_InventTransferLine.addLink(fieldNum(InventTransOrigin, InventTransId), fieldNum(InventTransferLine, InventTransId));
        qbd_InventTransferLine.addGroupByField(fieldNum(InventTransferLine, InventTransId));
        qbd_InventTransferLine.addGroupByField(fieldNum(InventTransferLine, UnitId));
        qbd_InventTransferLine.joinMode(JoinMode::OuterJoin);
        qbd_InventTransferLine.fetchMode(QueryFetchMode::One2One);
    }

    return query;
}

protected void fillTables()
{
    ttsBegin;

    this.storeBucketRecord();

    ITMTmpCreatorTable tmpShipCreatorTableLocal;
    ITMTmpCreatorLine tmpShipCreatorLineLocal;    
    tmpShipCreatorTableLocal.setTmpData(this.parmTmpShipCreatorTable());
    tmpShipCreatorLineLocal.setTmpData(this.parmTmpShipCreatorLine());

    delete_from tmpShipCreatorTableLocal;
    delete_from tmpShipCreatorLineLocal;

    Query query = this.buildQuery();

    QueryRun queryRun = new QueryRun(query);

    purchTableMap = new Map(Types::String, Types::Record);
    inventTransferTableMap = new Map(Types::String, Types::Record);

    Set existsTmpShipCreatorTable = new Set(Types::Container);
    SalesUnit salesUnit;

    while (queryRun.next())
    {
        InventTrans inventTrans = queryRun.get(tableNum(InventTrans));
        InventTransOrigin InventTransOrigin = queryRun.get(tableNum(inventTransOrigin));
        changeCompany (inventTrans.dataAreaId)
        {
            if (this.includeReference(inventTransOrigin.ReferenceCategory, inventTransOrigin.ReferenceId))
            {
                InventDim inventDim = queryRun.get(tableNum(InventDim));
                salesUnit = this.getSalesUnit(queryRun);
                if (!salesUnit)
                {
                    continue;
                }

                tmpShipCreatorLineLocal.clear();
                tmpShipCreatorLineLocal.PurchUnit = salesUnit;
                tmpShipCreatorLineLocal.InventTransId = inventTransOrigin.InventTransId;
                tmpShipCreatorLineLocal.InventTransType = inventTransOrigin.ReferenceCategory;
                tmpShipCreatorLineLocal.InventTransRefId = inventTransOrigin.ReferenceId;
                tmpShipCreatorLineLocal.DateStatus = inventTrans.DateExpected;
                tmpShipCreatorLineLocal.InventDimId = inventTrans.InventDimId;
                tmpShipCreatorLineLocal.InventSiteId = inventDim.InventSiteId;
                tmpShipCreatorLineLocal.InventLocationId = inventDim.InventLocationId;
                tmpShipCreatorLineLocal.InventQty = abs(inventTrans.Qty);
                tmpShipCreatorLineLocal.ShipDataArea = inventTrans.dataAreaId;
                this.initLineValues(tmpShipCreatorLineLocal, inventTrans.ItemId, tmpShipCreatorLineLocal.InventQty);
                tmpShipCreatorLineLocal.insert();

                container values;
                if (ETGOTMCreatorNoSplitHeaderByWarehouseFlight::instance().isEnabled())
                {
                    values = [inventTrans.DateExpected, inventTransOrigin.ReferenceCategory, inventTransOrigin.ReferenceId];
                }
                else
                {
                    values = [inventTrans.DateExpected, inventTransOrigin.ReferenceCategory, inventTransOrigin.ReferenceId, inventDim.InventSiteId, inventDim.InventLocationId];
                }

                if (!existsTmpShipCreatorTable.in(values))
                {
                    existsTmpShipCreatorTable.add(values);
                    tmpShipCreatorTableLocal.clear();
                    this.initTableValues(tmpShipCreatorTableLocal,
                                         inventTrans.DateExpected,
                                         inventTransOrigin.ReferenceCategory,
                                         inventTransOrigin.ReferenceId,
                                         inventDim.InventSiteId,
                                         inventDim.InventLocationId);
                    tmpShipCreatorTableLocal.insert();
                }
            }
        }
    }

    this.updateBucket();

    this.updateOverviewInformation();

    ttsCommit;
}

