    }

    this.updateBucket();

    this.updateOverviewInformation();

    ttsCommit;
}

public SalesUnit getSalesUnit(QueryRun _queryRun)
{
    InventTransOrigin InventTransOrigin = _queryRun.get(tableNum(inventTransOrigin));
    SalesUnit ret = '';

    if (inventTransOrigin.ReferenceCategory == InventTransType::Sales)
    {
        SalesLine salesLineLocal = _queryRun.get(tableNum(SalesLine));
        ret = salesLineLocal.SalesUnit;
    }
    else if (inventTransOrigin.ReferenceCategory == InventTransType::TransferOrderShip)
    {
        InventTransferLine transferLineLocal = _queryRun.get(tableNum(InventTransferLine));
        ret = transferLineLocal.UnitId;
    }

    return ret;
}

public NoYes includeReference(
    InventTransType _inventTransType,
    InventTransRefId _inventTransRefId)
{

    ITMCreatorOptions shipCreatorOptionsLocal = this.parmShipCreatorOptions();
    this.parmInventTransRefBuffer(null);

    switch (_inventTransType)
    {
        case InventTransType::Sales:
            SalesTable salesTable;

            if (purchTableMap.exists(salesTable.DataAreaId + _inventTransRefId))
            {
                salesTable = purchTableMap.lookup(salesTable.DataAreaId + _inventTransRefId);
            }

            if (shipCreatorOptionsLocal.parmDlvModeId())
            {
                if (!salesTable)
                {
                    salesTable = SalesTable::find(_inventTransRefId);
                    purchTableMap.insert(salesTable.DataAreaId + salesTable.SalesId, salesTable);
                }

                this.parmInventTransRefBuffer(salesTable);
                if (shipCreatorOptionsLocal.parmDlvModeId() != salesTable.DlvMode)
                {
                    return NoYes::No;
                }
            }

            if (shipCreatorOptionsLocal.parmVendRef())
            {
                if (!salesTable)
                {
                    salesTable = salesTable::find(_inventTransRefId);
                    purchTableMap.insert(salesTable.DataAreaId + salesTable.SalesId, salesTable);
                }
                this.parmInventTransRefBuffer(salesTable);
                if (shipCreatorOptionsLocal.parmVendRef() != salesTable.CustomerRef)
                {
                    return NoYes::No;
                }
            }

            break;

        case InventTransType::TransferOrderShip:

            if (shipCreatorOptionsLocal.parmVendRef())
            {
                return NoYes::No;
            }

            if (shipCreatorOptionsLocal.parmDlvModeId())
            {
                InventTransferTable inventTransferTable;

                if (inventTransferTableMap.exists(inventTransferTable.DataAreaId + _inventTransRefId))
                {
                    inventTransferTable = inventTransferTableMap.lookup(inventTransferTable.DataAreaId + _inventTransRefId);
                }
                else
                {
                    inventTransferTable = InventTransferTable::find(_inventTransRefId);
                }

                this.parmInventTransRefBuffer(inventTransferTable);
                if (shipCreatorOptionsLocal.parmDlvModeId() != inventTransferTable.DlvModeId)
                {
                    return NoYes::No;
                }
            }

            break;
    }

    return NoYes::Yes;
}

public void initLineValues(ITMTmpCreatorLine _tmpShipCreatorLine, ItemId _itemId, InventQty _qty)
{
    EcoResProductUnitConverter productUnitConverter;
    InventTable inventTable = InventTable::find(_itemId);
    Weight weight = inventTable.grossWeight();

    _tmpShipCreatorLine.ItemId = _itemId;

    _tmpShipCreatorLine.Volume = _qty * inventTable.grossVolume();

    if (!_tmpShipCreatorLine.Volume)
    {
        _tmpShipCreatorLine.VolumeMissing = NoYes::Yes;
    }

    _tmpShipCreatorLine.Weight = _qty * weight;

    if (!weight)
    {
        _tmpShipCreatorLine.WeightMissing = NoYes::Yes;
    }

    if (_tmpShipCreatorLine.InventTransType == InventTransType::TransferOrderReceive)
    {
        _tmpShipCreatorLine.PurchQty = _qty;
    }
    else
    {
        InventUnitId inventUnitId= inventTable.inventUnitId();

        if (inventUnitId == _tmpShipCreatorLine.PurchUnit)
        {
            _tmpShipCreatorLine.PurchQty = _qty;
        }
        else
        {
            productUnitConverter = EcoResProductUnitConverter::newGivenUnitSymbolsForReleasedProduct(
                                                _tmpShipCreatorLine.ItemId,
                                                _tmpShipCreatorLine.InventDimId,
                                                inventUnitId,
                                                _tmpShipCreatorLine.PurchUnit,
                                                NoYes::Yes);
            _tmpShipCreatorLine.PurchQty = productUnitConverter.convertValue(_qty);
        }
    }
}
